namespace sv_8728d3d371cc40f9a7b0f5ce689ed7cd.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public sealed class ShipmentDetails
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
    public required string Location { get; init; }
}

using sv_8728d3d371cc40f9a7b0f5ce689ed7cd.Client.Services;

namespace sv_8728d3d371cc40f9a7b0f5ce689ed7cd.Services;

public sealed class SimulatedShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), Description = "Departed facility", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 6, 15, 0, TimeSpan.Zero), Description = "Arrived at hub", Location = "Chicago, IL" },
            ]
        },
        ["TRK-002"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 9, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 11, 0, 0, TimeSpan.Zero), Description = "In transit", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 16, 45, 0, TimeSpan.Zero), Description = "Out for delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 18, 20, 0, TimeSpan.Zero), Description = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["TRK-003"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 15, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 10, 0, 0, TimeSpan.Zero), Description = "Label created", Location = "Dallas, TX" },
            ]
        }
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

using System.Net.Http.Json;

namespace sv_8728d3d371cc40f9a7b0f5ce689ed7cd.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API when running on WebAssembly.
/// </summary>
public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct))!;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_8728d3d371cc40f9a7b0f5ce689ed7cd.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Tracking History</h3>
    <table>
        <thead>
            <tr>
                <th>Time</th>
                <th>Description</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Description</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;
    private string _lastLoadedTrackingNumber = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase))
            return;

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposing — silently stop.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        _lastLoadedTrackingNumber = string.Empty;
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

